boolean process(Token t, HtmlTreeBuilder tb) {
    switch (t.type) {
        case Character: {
            Token.Character c = t.asCharacter();
            if (c.getData().equals(nullString)) {
                // todo confirm that check
                tb.error(this);
                return false;
            } else if (tb.framesetOk() && isWhitespace(c)) { // don't check if whitespace if frames already closed
                tb.reconstructFormattingElements();
                tb.insert(c);
            } else {
                tb.reconstructFormattingElements();
                tb.insert(c);
                tb.framesetOk(false);
            }
            break;
        }
        case Comment: {
            tb.insert(t.asComment());
            break;
        }
        case Doctype: {
            tb.error(this);
            return false;
        }
        case StartTag:
            return inBodyStartTag(t, tb);
        case EndTag:
            return inBodyEndTag(t, tb);
        case EOF:
            // todo: error if stack contains something not dd, dt, li, p, tbody, td, tfoot, th, thead, tr, body, html
            // stop parsing
            break;
    }
    return true;
}

private Element popStackToSuitableContainer(Tag tag) {
    while (stack.size() > 0) {
        if (stack.getLast().getTag().canContain(tag))
            return stack.getLast();
        else
            stack.removeLast();
    }
    return null;
}

private Element popStackToSuitableContainer(Tag tag) {
    while (!stack.isEmpty()) {
        if (last().getTag().canContain(tag))
            return last();
        else
            stack.removeLast();
    }
    return null;
}

