static void escape(Appendable accum, String string, Document.OutputSettings out,
                   boolean inAttribute, boolean normaliseWhite, boolean stripLeadingWhite) throws IOException {

    boolean lastWasWhite = false;
    boolean reachedNonWhite = false;
    final EscapeMode escapeMode = out.escapeMode();
    final CharsetEncoder encoder = out.encoder();
    final CoreCharset coreCharset = CoreCharset.byName(encoder.charset().name());
    final int length = string.length();

    int codePoint;
    for (int offset = 0; offset < length; offset += Character.charCount(codePoint)) {
        codePoint = string.codePointAt(offset);

        if (normaliseWhite) {
            if (StringUtil.isWhitespace(codePoint)) {
                if ((stripLeadingWhite && !reachedNonWhite) || lastWasWhite)
                    continue;
                accum.append(' ');
                lastWasWhite = true;
                continue;
            } else {
                lastWasWhite = false;
                reachedNonWhite = true;
            }
        }
        // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
        if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
            final char c = (char) codePoint;
            // html specific and required escapes:
            switch (c) {
                case '&':
                    accum.append("&amp;");
                    break;
                case 0xA0:
                    if (escapeMode != EscapeMode.xhtml)
                        accum.append("&nbsp;");
                    else
                        accum.append("&#xa0;");
                    break;
                case '<':
                    // escape when in character data or when in a xml attribue val; not needed in html attr val
                    if (!inAttribute || escapeMode == EscapeMode.xhtml)
                        accum.append("&lt;");
                    else
                        accum.append(c);
                    break;
                case '>':
                    if (!inAttribute)
                        accum.append("&gt;");
                    else
                        accum.append(c);
                    break;
                case '"':
                    if (inAttribute)
                        accum.append("&quot;");
                    else
                        accum.append(c);
                    break;
                default:
                    if (canEncode(coreCharset, c, encoder))
                        accum.append(c);
                    else
                        appendEncoded(accum, escapeMode, codePoint);
            }
        } else {
            final String c = new String(Character.toChars(codePoint));
            if (encoder.canEncode(c)) // uses fallback encoder for simplicity
                accum.append(c);
            else
                appendEncoded(accum, escapeMode, codePoint);
        }
    }
}

public Document parse() throws IOException {
    Validate.isTrue(executed, "Request must be executed (with .execute(), .get(), or .post() before parsing response");
    InputStream stream = bodyStream;
    if (byteData != null) { // bytes have been read in to the buffer, parse that
        stream = new ByteArrayInputStream(byteData.array());
        inputStreamRead = false; // ok to reparse if in bytes
    }
    Validate.isFalse(inputStreamRead, "Input stream already read and parsed, cannot re-read.");
    Document doc = DataUtil.parseInputStream(stream, charset, url.toExternalForm(), req.parser());
    doc.connection(new HttpConnection(req, this)); // because we're static, don't have the connection obj. // todo - maybe hold in the req?
    charset = doc.outputSettings().charset().name(); // update charset from meta-equiv, possibly
    inputStreamRead = true;
    safeClose();
    return doc;
}

public void run() {
	synchronized ( this ) {
		if( selectorthread != null )
			throw new IllegalStateException( getClass().getName() + " can only be started once." );
		selectorthread = Thread.currentThread();
		if( isclosed.get() ) {
			return;
		}
	}
	selectorthread.setName( "WebSocketSelector-" + selectorthread.getId() );
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		ServerSocket socket = server.socket();
		socket.setReceiveBufferSize( WebSocketImpl.RCVBUF );
		socket.setReuseAddress( isReuseAddr() );
		socket.bind( address );
		selector = Selector.open();
		server.register( selector, server.validOps() );
		startConnectionLostTimer();
		onStart();
	} catch ( IOException ex ) {
		handleFatal( null, ex );
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						// Object o = key.attachment();
						continue;
					}

					if( key.isAcceptable() ) {
						if( !onConnect( key ) ) {
							key.cancel();
							continue;
						}

						SocketChannel channel = server.accept();
						if(channel==null){
							continue;
						}
						channel.configureBlocking( false );
						Socket socket = channel.socket();
						socket.setTcpNoDelay( isTcpNoDelay() );
						socket.setKeepAlive( true );
						WebSocketImpl w = wsf.createWebSocket( this, drafts );
						w.setSelectionKey(channel.register( selector, SelectionKey.OP_READ, w ));
						try {
							w.channel = wsf.wrapChannel( channel, w.getSelectionKey() );
							i.remove();
							allocateBuffers( w );
							continue;
						} catch (IOException ex) {
							if( w.getSelectionKey() != null )
								w.getSelectionKey().cancel();

							handleIOException( w.getSelectionKey(), null, ex );
						}
						continue;
					}

					if( key.isReadable() ) {
						conn = (WebSocketImpl) key.attachment();
						ByteBuffer buf = takeBuffer();
						if(conn.channel == null){
							if( key != null )
								key.cancel();

							handleIOException( key, conn, new IOException() );
							continue;
						}
						try {
							if( SocketChannelIOHelper.read( buf, conn, conn.channel ) ) {
								if( buf.hasRemaining() ) {
									conn.inQueue.put( buf );
									queue( conn );
									i.remove();
									if( conn.channel instanceof WrappedByteChannel ) {
										if( ( (WrappedByteChannel) conn.channel ).isNeedRead() ) {
											iqueue.add( conn );
										}
									}
								} else
									pushBuffer( buf );
							} else {
								pushBuffer( buf );
							}
						} catch ( IOException e ) {
							pushBuffer( buf );
							throw e;
						}
					}
					if( key.isWritable() ) {
						conn = (WebSocketImpl) key.attachment();
						if( SocketChannelIOHelper.batch( conn, conn.channel ) ) {
							if( key.isValid() )
								key.interestOps( SelectionKey.OP_READ );
						}
					}
				}
				while ( !iqueue.isEmpty() ) {
					conn = iqueue.remove( 0 );
					WrappedByteChannel c = ( (WrappedByteChannel) conn.channel );
					ByteBuffer buf = takeBuffer();
					try {
						if( SocketChannelIOHelper.readMore( buf, conn, c ) )
							iqueue.add( conn );
						if( buf.hasRemaining() ) {
							conn.inQueue.put( buf );
							queue( conn );
						} else {
							pushBuffer( buf );
						}
					} catch ( IOException e ) {
						pushBuffer( buf );
						throw e;
					}

				}
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				return;// FIXME controlled shutdown (e.g. take care of buffermanagement)
			}
		}

	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		stopConnectionLostTimer();
		if( decoders != null ) {
			for( WebSocketWorker w : decoders ) {
				w.interrupt();
			}
		}
		if( selector != null ) {
			try {
				selector.close();
			} catch ( IOException e ) {
				log.error( "IOException during selector.close", e );
				onError( null, e );
			}
		}
		if( server != null ) {
			try {
				server.close();
			} catch ( IOException e ) {
				log.error( "IOException during server.close", e );
				onError( null, e );
			}
		}
	}
}

@Override
HttpConnection.Response execute() throws IOException {
    try {
        HttpClient.Builder builder = HttpClient.newBuilder();
        Proxy proxy = req.proxy();
        if (proxy != null) builder.proxy(new ProxyWrap(proxy));
        builder.followRedirects(HttpClient.Redirect.NEVER); // customized redirects
        //builder.connectTimeout(Duration.ofMillis(req.timeout()/2)); // jsoup timeout is total connect + all reads
        // todo - how to handle socketfactory? HttpClient wants SSLContext...
        if (req.authenticator != null) {
            AuthenticationHandler.AuthShim handler = new RequestAuthHandler();
            handler.enable(req.authenticator, builder);
        }
        HttpClient client = builder.build();

        HttpRequest.Builder reqBuilder =
            HttpRequest.newBuilder(req.url.toURI()).method(req.method.name(), requestBody(req));
        if (req.timeout() > 0) reqBuilder.timeout(
            Duration.ofMillis(req.timeout())); // infinite if unset (UrlConnection / jsoup uses 0 for same)
        CookieUtil.applyCookiesToRequest(req, reqBuilder::header);

        // headers:
        for (Map.Entry<String, List<String>> header : req.multiHeaders().entrySet()) {
            for (String value : header.getValue()) {
                reqBuilder.header(header.getKey(), value);
            }
        }

        HttpRequest hReq = reqBuilder.build();
        hRes = client.send(hReq, HttpResponse.BodyHandlers.ofInputStream());
        HttpHeaders headers = hRes.headers();

        // set up the response
        Response res = new Response(req);
        res.executor = this;
        res.method = Connection.Method.valueOf(hRes.request().method());
        res.url = hRes.uri().toURL();
        res.statusCode = hRes.statusCode();
        res.contentType = headers.firstValue("content-type").orElse("");
        long length = headers.firstValueAsLong("content-length").orElse(-1);
        res.contentLength = length < Integer.MAX_VALUE ? (int) length : -1;
        res.prepareResponse(headers.map(), prevRes);

        return res;
    } catch (IOException e) {
        safeClose();
        throw e;
    } catch (InterruptedException e) {
        safeClose();
        throw new IOException(e);
    } catch (URISyntaxException e) {
        throw new IllegalArgumentException("Malformed URL: " + req.url, e);
    }
}

