	private Framedata translateSingleFrame( ByteBuffer buffer ) throws IncompleteException, InvalidDataException {
		if (buffer == null)
			throw new IllegalArgumentException();
		int maxpacketsize = buffer.remaining();
		int realpacketsize = 2;
		translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);
		byte b1 = buffer.get( /*0*/ );
		boolean fin = b1 >> 8 != 0;
		boolean rsv1 = ( b1 & 0x40 ) != 0;
		boolean rsv2 = ( b1 & 0x20 ) != 0;
		boolean rsv3 = ( b1 & 0x10 ) != 0;
		byte b2 = buffer.get( /*1*/ );
		boolean mask = ( b2 & -128 ) != 0;
		int payloadlength = ( byte ) ( b2 & ~( byte ) 128 );
		Opcode optcode = toOpcode( ( byte ) ( b1 & 15 ) );

		if( !( payloadlength >= 0 && payloadlength <= 125 ) ) {
            payloadlength = translateSingleFramePayloadLength(buffer, optcode, payloadlength ,maxpacketsize, realpacketsize);
		}
		translateSingleFrameCheckLengthLimit(payloadlength);
		realpacketsize += ( mask ? 4 : 0 );
		realpacketsize += payloadlength;
		translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);

		ByteBuffer payload = ByteBuffer.allocate( checkAlloc( payloadlength ) );
		if( mask ) {
			byte[] maskskey = new byte[4];
			buffer.get( maskskey );
			for( int i = 0; i < payloadlength; i++ ) {
				payload.put( ( byte ) ( buffer.get( /*payloadstart + i*/ ) ^ maskskey[i % 4] ) );
			}
		} else {
			payload.put( buffer.array(), buffer.position(), payload.limit() );
			buffer.position( buffer.position() + payload.limit() );
		}

		FramedataImpl1 frame = FramedataImpl1.get( optcode );
		frame.setFin( fin );
		frame.setRSV1( rsv1 );
		frame.setRSV2( rsv2 );
		frame.setRSV3( rsv3 );
		payload.flip();
		frame.setPayload( payload );
		getExtension().isFrameValid(frame);
		getExtension().decodeFrame(frame);
		if (log.isTraceEnabled())
			log.trace( "afterDecoding({}): {}", frame.getPayloadData().remaining(), ( frame.getPayloadData().remaining() > 1000 ? "too big to display" : new String( frame.getPayloadData().array() ) ) );
		frame.isValid();
		return frame;
	}

/**
 * Gets the combined text of this element and all its children.
 * 
 * @return unencoded text, or empty string if none.
 */
public String text() {
    StringBuilder sb = new StringBuilder();

    for (Node childNode : childNodes) {
        if (childNode instanceof TextNode) {
            TextNode textNode = (TextNode) childNode;
            sb.append(textNode.getWholeText());
        } else if (childNode instanceof Element) {
            Element element = (Element) childNode;
            String elementText = element.text();
            if (element.isBlock() && sb.length() > 0 && elementText.length() > 0)
                sb.append(" ");
            sb.append(elementText);
        }
    }
    return sb.toString();
}

/**
 * Private method to cache all the frames to improve memory footprint and conversion time
 * @param data the data to broadcast
 * @param clients the clients to send the message to
 */
private void doBroadcast(Object data, Collection<WebSocket> clients) {
	String sData = null;
	if (data instanceof String) {
		sData = (String)data;
	}
	ByteBuffer bData = null;
	if (data instanceof ByteBuffer) {
		bData = (ByteBuffer)data;
	}
	if (sData == null && bData == null) {
		return;
	}
	Map<Draft, List<Framedata>> draftFrames = new HashMap<Draft, List<Framedata>>();
	for( WebSocket client : clients ) {
		if( client != null ) {
			Draft draft = client.getDraft();
			if( !draftFrames.containsKey( draft ) ) {
				List<Framedata> frames = null;
				if (sData != null) {
					frames = draft.createFrames( sData, false );
				}
				if (bData != null) {
					frames = draft.createFrames( bData, false );
				}
				if (frames != null) {
					draftFrames.put(draft, frames);
				}
			}
			try {
				client.sendFrame( draftFrames.get( draft ) );
			} catch ( WebsocketNotConnectedException e ) {
				//Ignore this exception in this case
			}
		}
	}
}

private boolean tryToConnect(InetSocketAddress remote) {
  // The WebSocket constructor expects a SocketChannel that is
  // non-blocking, and has a Selector attached to it.
  try {
    client = SocketChannel.open();
    client.configureBlocking(false);
    client.connect(remote);

    selector = Selector.open();

    this.conn = new WebSocket(client, new LinkedBlockingQueue<ByteBuffer>(), this);
    // At first, we're only interested in the 'CONNECT' keys.
    client.register(selector, SelectionKey.OP_CONNECT);

  } catch (IOException ex) {
  	onIOError(ex);
    return false;
  }

  return true;
}

