/**
 * Returns whether the handshake phase has is completed.
 * In case of a broken handshake this will be never the case.
 **/
private boolean decodeHandshake( ByteBuffer socketBufferNew ) {
	ByteBuffer socketBuffer;
	if( tmpHandshakeBytes.capacity() == 0 ) {
		socketBuffer = socketBufferNew;
	} else {
		if( tmpHandshakeBytes.remaining() < socketBufferNew.remaining() ) {
			ByteBuffer buf = ByteBuffer.allocate( tmpHandshakeBytes.capacity() + socketBufferNew.remaining() );
			tmpHandshakeBytes.flip();
			buf.put( tmpHandshakeBytes );
			tmpHandshakeBytes = buf;
		}

		tmpHandshakeBytes.put( socketBufferNew );
		tmpHandshakeBytes.flip();
		socketBuffer = tmpHandshakeBytes;
	}
	socketBuffer.mark();
	try {
		if( draft == null ) {
			HandshakeState isflashedgecase = isFlashEdgeCase( socketBuffer );
			if( isflashedgecase == HandshakeState.MATCHED ) {
				try {
					write( Collections.singletonList( ByteBuffer.wrap(Charsetfunctions.utf8Bytes(wsl.getFlashPolicy(this)))));
					close(CloseFrame.FLASHPOLICY, "");
				} catch ( InvalidDataException e ) {
					close( CloseFrame.ABNORMAL_CLOSE, "remote peer closed connection before flashpolicy could be transmitted", true );
				}
				return false;
			}
		}
		HandshakeState handshakestate;

		try {
			if( role == Role.SERVER ) {
				if( draft == null ) {
					for( Draft d : knownDrafts ) {
						d = d.copyInstance();
						try {
							d.setParseMode( role );
							socketBuffer.reset();
							Handshakedata tmphandshake = d.translateHandshake( socketBuffer );
							if( !( tmphandshake instanceof ClientHandshake ) ) {
								closeConnectionDueToWrongHandshake( new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "wrong http function" ));
								return false;
							}
							ClientHandshake handshake = ( ClientHandshake ) tmphandshake;
							handshakestate = d.acceptHandshakeAsServer( handshake );
							if( handshakestate == HandshakeState.MATCHED ) {
								resourceDescriptor = handshake.getResourceDescriptor();
								ServerHandshakeBuilder response;
								try {
									response = wsl.onWebsocketHandshakeReceivedAsServer( this, d, handshake );
								} catch ( InvalidDataException e ) {
									closeConnectionDueToWrongHandshake( e );
									return false;
								} catch ( RuntimeException e ) {
									wsl.onWebsocketError( this, e );
									closeConnectionDueToInternalServerError( e );
									return false;
								}
								write( d.createHandshake( d.postProcessHandshakeResponseAsServer( handshake, response ), role ) );
								draft = d;
								open( handshake );
								return true;
							}
						} catch ( InvalidHandshakeException e ) {
							// go on with an other draft
						}
					}
					if( draft == null ) {
						closeConnectionDueToWrongHandshake( new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "no draft matches"));
					}
					return false;
				} else {
					// special case for multiple step handshakes
					Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
					if( !( tmphandshake instanceof ClientHandshake ) ) {
						flushAndClose( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
						return false;
					}
					ClientHandshake handshake = ( ClientHandshake ) tmphandshake;
					handshakestate = draft.acceptHandshakeAsServer( handshake );

					if( handshakestate == HandshakeState.MATCHED ) {
						open( handshake );
						return true;
					} else {
						close( CloseFrame.PROTOCOL_ERROR, "the handshake did finaly not match" );
					}
					return false;
				}
			} else if( role == Role.CLIENT ) {
				draft.setParseMode( role );
				Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
				if( !( tmphandshake instanceof ServerHandshake ) ) {
					flushAndClose( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
					return false;
				}
				ServerHandshake handshake = ( ServerHandshake ) tmphandshake;
				handshakestate = draft.acceptHandshakeAsClient( handshakerequest, handshake );
				if( handshakestate == HandshakeState.MATCHED ) {
					try {
						wsl.onWebsocketHandshakeReceivedAsClient( this, handshakerequest, handshake );
					} catch ( InvalidDataException e ) {
						flushAndClose( e.getCloseCode(), e.getMessage(), false );
						return false;
					} catch ( RuntimeException e ) {
						wsl.onWebsocketError( this, e );
						flushAndClose( CloseFrame.NEVER_CONNECTED, e.getMessage(), false );
						return false;
					}
					open( handshake );
					return true;
				} else {
					close( CloseFrame.PROTOCOL_ERROR, "draft " + draft + " refuses handshake" );
				}
			}
		} catch ( InvalidHandshakeException e ) {
			close( e );
		}
	} catch ( IncompleteHandshakeException e ) {
		if( tmpHandshakeBytes.capacity() == 0 ) {
			socketBuffer.reset();
			int newsize = e.getPreferedSize();
			if( newsize == 0 ) {
				newsize = socketBuffer.capacity() + 16;
			} else {
				assert ( e.getPreferedSize() >= socketBuffer.remaining() );
			}
			tmpHandshakeBytes = ByteBuffer.allocate( newsize );

			tmpHandshakeBytes.put( socketBufferNew );
			// tmpHandshakeBytes.flip();
		} else {
			tmpHandshakeBytes.position( tmpHandshakeBytes.limit() );
			tmpHandshakeBytes.limit( tmpHandshakeBytes.capacity() );
		}
	}
	return false;
}

static void escape(Appendable accum, String string, OutputSettings out,
                   boolean forText, boolean forAttribute, boolean normaliseWhite, boolean stripLeadingWhite, boolean trimTrailing) throws IOException {

    boolean lastWasWhite = false;
    boolean reachedNonWhite = false;
    final EscapeMode escapeMode = out.escapeMode();
    final CharsetEncoder encoder = out.encoder();
    final CoreCharset coreCharset = out.coreCharset; // init in out.prepareEncoder()
    final int length = string.length();

    int codePoint;
    boolean skipped = false;
    for (int offset = 0; offset < length; offset += Character.charCount(codePoint)) {
        codePoint = string.codePointAt(offset);

        if (normaliseWhite) {
            if (StringUtil.isWhitespace(codePoint)) {
                if (stripLeadingWhite && !reachedNonWhite) continue;
                if (lastWasWhite) continue;
                if (trimTrailing) {
                    skipped = true;
                    continue;
                }
                accum.append(' ');
                lastWasWhite = true;
                continue;
            } else {
                lastWasWhite = false;
                reachedNonWhite = true;
                if (skipped) {
                    accum.append(' '); // wasn't the end, so need to place a normalized space
                    skipped = false;
                }
            }
        }
        // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
        if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
            final char c = (char) codePoint;
            // html specific and required escapes:
            switch (c) {
                case '&':
                    accum.append("&amp;");
                    break;
                case 0xA0:
                    if (escapeMode != EscapeMode.xhtml)
                        accum.append("&nbsp;");
                    else
                        accum.append("&#xa0;");
                    break;
                case '<':
                    // escape when in character data or when in a xml attribute val or XML syntax; not needed in html attr val
                    if (forText || escapeMode == EscapeMode.xhtml || out.syntax() == Syntax.xml)
                        accum.append("&lt;");
                    else
                        accum.append(c);
                    break;
                case '>':
                    if (forText)
                        accum.append("&gt;");
                    else
                        accum.append(c);
                    break;
                case '"':
                    if (forAttribute)
                        accum.append("&quot;");
                    else
                        accum.append(c);
                    break;
                case '\'':
                    if (forAttribute && forText) { // special case for the Entities.escape(string) method when we are maximally escaping. Otherwise, because we output attributes in "", there's no need to escape.
                        if (escapeMode == EscapeMode.xhtml)
                            accum.append("&#x27;");
                        else
                            accum.append("&apos;");
                    }
                    else
                        accum.append(c);
                    break;
                // we escape ascii control <x20 (other than tab, line-feed, carriage return)  for XML compliance (required) and HTML ease of reading (not required) - https://www.w3.org/TR/xml/#charsets
                case 0x9:
                case 0xA:
                case 0xD:
                    accum.append(c);
                    break;
                default:
                    if (c < 0x20 || !canEncode(coreCharset, c, encoder))
                        appendEncoded(accum, escapeMode, codePoint);
                    else
                        accum.append(c);
            }
        } else {
            final String c = new String(Character.toChars(codePoint));
            if (encoder.canEncode(c)) // uses fallback encoder for simplicity
                accum.append(c);
            else
                appendEncoded(accum, escapeMode, codePoint);
        }
    }
}

public void setCode(int code) {
    this.code = code;
    // CloseFrame.TLS_ERROR is not allowed to be transfered over the wire
    if (code == CloseFrame.TLS_ERROR) {
        this.code = CloseFrame.NOCODE;
        this.reason = "";
    }
    updatePayload();
}

private static void appendEscaped(Appendable accum, OutputSettings out, int options,
    int codePoint, EscapeMode escapeMode, CharsetEncoder encoder, CoreCharset coreCharset) throws IOException {

    // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
    final char c = (char) codePoint;
    if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
        // html specific and required escapes:
        switch (c) {
            case '&':
                accum.append("&amp;");
                break;
            case 0xA0:
                appendNbsp(accum, escapeMode);
                break;
            case '<':
                // escape when in character data or when in a xml attribute val or XML syntax; not needed in html attr val
                appendLt(accum, options, escapeMode, out);
                break;
            case '>':
                if ((options & ForText) != 0) accum.append("&gt;");
                else accum.append(c);
                break;
            case '"':
                if ((options & ForAttribute) != 0) accum.append("&quot;");
                else accum.append(c);
                break;
            case '\'':
                // special case for the Entities.escape(string) method when we are maximally escaping. Otherwise, because we output attributes in "", there's no need to escape.
                appendApos(accum, options, escapeMode);
                break;
            // we escape ascii control <x20 (other than tab, line-feed, carriage return) for XML compliance (required) and HTML ease of reading (not required) - https://www.w3.org/TR/xml/#charsets
            case 0x9:
            case 0xA:
            case 0xD:
                accum.append(c);
                break;
            default:
                if (c < 0x20 || !canEncode(coreCharset, c, encoder)) appendEncoded(accum, escapeMode, codePoint);
                else accum.append(c);
        }
    } else {
        if (canEncode(coreCharset, c, encoder)) {
            String s = new String(Character.toChars(codePoint));
            accum.append(s);
        } else appendEncoded(accum, escapeMode, codePoint);
    }
}

/**
 * Gets the Document associated with this Node. 
 * @return the Document associated with this Node, or null if there is no such Document.
 */
public Document ownerDocument() {
    Node node = this;
    while (true) {
        if (node instanceof Document)
            return (Document) node;
        else if (node.parentNode == null)
            return null;
        else
            node = node.parentNode;
    }
}

